import {OwnerIdentifier, OwnershipInformation} from "./OwnerInfo";
import DOFOptions from "./DOFOptions";
import DOFArbiterPolicy from "./DOFArbiterPolicy";

import log from '../log';

/**
 * @interface PriorityConfig
 * @memberof jibo.dofarbiter
 * @prop priorityForUnknownLabels {number} Priority to give labeled commands whose label is not registered in the priorityEntries map.
 * @prop priorityForDirectUsers {number} 	Priority to give commands that came outside the DOFArbiter interface (E.g., direct
 * 				animation-utilities usage).  Note: these type of commands will always happen, as they are not
 * 				mediated here, so the priority is only of use to know when to interrupt them, rather
 * 				than what they will interrupt.
 * @prop priorityEntries {Array<jibo.dofarbiter.OwnerPriority>} Set of priorities to assign different requesters; higher number requesters will interrupt
 * 				lower number requests.
 */
export interface PriorityConfig{
	priorityForUnknownLabels:number;
	priorityForDirectUsers:number;
	priorityEntries:{owner:OwnerIdentifier, priority:number}[];
}

/**
 * @interface OwnerPriority
 * @memberof jibo.dofarbiter
 * @prop owner {jibo.dofarbiter.OwnerIdentifier}
 * @prop priority {number}
 */
interface OwnerPriority{
	owner:OwnerIdentifier;
	priority:number;
}

/**
 * @class DOFArbiterPriorityPolicy
 * @memberof jibo.dofarbiter
 * @intdocs
 */
export class DOFArbiterPriorityPolicy implements DOFArbiterPolicy{

	priorityMap = new Map<OwnerIdentifier, number>();
	unknownRequesterIDPriority: number;
	debug = false;
	debugPrintFailedGrab = false; //for when you want to only print on the failed dof grab

	constructor(config:PriorityConfig, directCommandsLabel:OwnerIdentifier){
		this.unknownRequesterIDPriority = config.priorityForUnknownLabels;
		this.priorityMap = new Map<OwnerIdentifier, number>();
		for(let i = 0; i < config.priorityEntries.length; i++){
			this.priorityMap.set(config.priorityEntries[i].owner, config.priorityEntries[i].priority);
		}
		this.priorityMap.set(directCommandsLabel, config.priorityForDirectUsers);
	}

	/**
	 * @method jibo.dofarbiter.DOFArbiterPriorityPolicy#acquire
	 * @description Check which dofs can be used by requester.  Dofs which are available for use by requester will be returned.
	 * @param {jibo.dofarbiter.OwnerIdentifier} requester - the requester
	 * @param {string[]} dofs - the desired dofs
	 * @param {Map} dofOwners - Map of `string` to `OwnershipInformation`. Structure with the current dof ownership information
	 * @param {jibo.dofarbiter.DOFOptions} options - options that might affect this request
	 * @return {string[]} the subset of provided dofs that are available for immediate acquisition
	 */
	acquire(requester:OwnerIdentifier, dofs:string[], dofOwners: Map<string,OwnershipInformation>, options:DOFOptions):string[]{
		let allowedDOFs: string[] = [];
		let deniedDOFs: string[] = [];
		let deniedDOFOwners = new Set<string>();
		let newPriority = this.priorityMap.get(requester);
		if (this.debug) { log.debug(`Requester ${requester} has priority ${newPriority} ${(newPriority === undefined ? `(= ${this.unknownRequesterIDPriority})` : "")}`); }
		if(newPriority === undefined){
			newPriority = this.unknownRequesterIDPriority;
		}
		for(let i = 0; i < dofs.length; i++){
			let currentOwnerInfo = <OwnershipInformation>dofOwners.get(dofs[i]);
			if(!currentOwnerInfo){
				// this should _never_ happen
				log.warn(`No ownership info found for dof ${dofs[i]} requested by ${requester}; all requested DOFs: [${dofs}]`);
				let currentDOFOwners: string[] = [];
				let iter = dofOwners.entries(); //don't use for of for optimizer
				let nextEntry;
				while(!(nextEntry = iter.next()).done){
					let dofName:string = nextEntry.value[0];
					let info:OwnershipInformation = nextEntry.value[1];
					if(info){
						currentDOFOwners.push(`${dofName}: ${info.owner} (${(info.ownerInstance && info.ownerInstance.getName ? info.ownerInstance.getName() : "")})`);
					}else{
						currentDOFOwners.push(`${dofName}: empty info (${info})`);
					}
				}
				log.warn(`Current ownership info for all known DOFs: [${currentDOFOwners}]`);
				log.warn(`Request will be rejected; stack is: ${new Error().stack}`);
				return [];
			}
			if (this.debug) { log.debug(`Current owner for ${dofs[i]} is ${currentOwnerInfo.owner}, priority: ${(currentOwnerInfo.owner === null ? "N/A" : this.priorityMap.get(currentOwnerInfo.owner))}`); }
			let currentPriority;
			if(currentOwnerInfo.owner === requester ||
				currentOwnerInfo.owner === null ||
				(currentPriority = this.priorityMap.get(currentOwnerInfo.owner)) < newPriority ||
				(currentPriority === undefined && this.unknownRequesterIDPriority < newPriority)){
				//dof is either not owned, owned by us, or owned by something with less priority than us
				allowedDOFs.push(dofs[i]);
			}else{
				if (this.debug || this.debugPrintFailedGrab) { log.debug(`Requester ${requester} denied dof ${dofs[i]}, owned by ${currentOwnerInfo.owner} (${(currentOwnerInfo.ownerInstance && currentOwnerInfo.ownerInstance.getName ? currentOwnerInfo.ownerInstance.getName() : "")}) with priority ${currentPriority} ${(currentPriority === undefined ? `(=${this.unknownRequesterIDPriority})` : "")}`); }
				deniedDOFs.push(dofs[i]);
				deniedDOFOwners.add(`(${currentOwnerInfo.owner}, ${((currentOwnerInfo.ownerInstance && currentOwnerInfo.ownerInstance.getName) ? currentOwnerInfo.ownerInstance.getName() : currentOwnerInfo.owner)}, ` +
					`${(currentPriority === undefined ? this.unknownRequesterIDPriority : currentPriority)})`);
			}
		}
		// At least one dof is not included
		if (deniedDOFs.length > 0) {
			if (options.allOrNothing) {
				if (newPriority >= this.unknownRequesterIDPriority) {
					log.info(`Requester:  ${requester}  was rejected because DOFs:  [${deniedDOFs}]  are held by owners:  [${Array.from(deniedDOFOwners)}]`);
				}
				allowedDOFs = [];
			} else {
				if (newPriority >= this.unknownRequesterIDPriority) {
					log.info(`Requester:  ${requester}  did not receive DOFs:  [${deniedDOFs}]  because they are held by owners:  [${Array.from(deniedDOFOwners)}]`);
				}
			}
		}

		return allowedDOFs;
	}

	/**
	 * Generate a list of owners in priority order, low to high, including only the owners
	 * passed in.
	 * @method jibo.dofarbiter.DOFArbiterPriorityPolicy#ownerPriorityOrder
	 * @param {OwnerIdentifier[]} owners - owners to list in order
	 * @returns {OwnerIdentifier[]} in order (low to high) of owners based on priority
	 */
	ownerPriorityOrder(owners:OwnerIdentifier[]):OwnerIdentifier[]{
		let ownersWithPriority:OwnerPriority[] = [];
		for(let i = 0; i < owners.length; i++){
			let owner = owners[i];
			let ownerPriority = this.priorityMap.get(owner);
			if(ownerPriority === undefined){
				ownerPriority = this.unknownRequesterIDPriority;
			}
			ownersWithPriority.push({owner:owner, priority:ownerPriority});
		}
		ownersWithPriority.sort(function(a,b){return a.priority - b.priority;});
		let ownersInOrder: OwnerIdentifier[] = [];
		for(let i = 0; i < ownersWithPriority.length; i++){
			ownersInOrder.push(ownersWithPriority[i].owner);
		}
		return ownersInOrder;
	}

}
